using System;

public delegate void DisplayHandler(string message);

class MessageProcessor
{
    public void ProcessMessage(DisplayHandler display)
    {
        display("Mesaj alındı!");
    }
}

class Program
{
    static void Main(string[] args)
    {
        MessageProcessor processor = new MessageProcessor();

        // Lambda ifadəsi ilə deleqata metod təyin etmək
        processor.ProcessMessage(msg => Console.WriteLine(msg));
    }
}
// Output:
// Mesaj alındı!

using System;

public delegate int MathOperation(int a, int b);

class Calculator
{
    public int Compute(MathOperation operation, int x, int y)
    {
        return operation(x, y);
    }
}

class Program
{
    static void Main(string[] args)
    {
        Calculator calc = new Calculator();

        // Toplama üçün lambda ifadəsi
        int sum = calc.Compute((a, b) => a + b, 5, 3);
        Console.WriteLine($"Toplam: {sum}");

        // Çıxma üçün lambda ifadəsi
        int difference = calc.Compute((a, b) => a - b, 5, 3);
        Console.WriteLine($"Fərq: {difference}");
    }
}
// Output:
// Toplam: 8
// Fərq: 2

using System;
using System.Linq;

class Program
{
    static void Main(string[] args)
    {
        int[] numbers = { 1, 2, 3, 4, 5, 6 };

        // Lambda ilə cüt ədədləri filtrləmək
        var evenNumbers = numbers.Where(n => n % 2 == 0);
        Console.WriteLine("Cüt ədədlər: " + string.Join(", ", evenNumbers));

        // Lambda ilə kvadratları hesablamaq
        var squares = numbers.Select(n => n * n);
        Console.WriteLine("Kvadratlar: " + string.Join(", ", squares));
    }
}
// Output:
// Cüt ədədlər: 2, 4, 6
// Kvadratlar: 1, 4, 9, 16, 25, 36

using System;

public delegate void PrintHandler(int number);

class Printer
{
    public void Print(PrintHandler print)
    {
        print(10);
    }
}

class Program
{
    static void Main(string[] args)
    {
        Printer printer = new Printer();

        // Anonim metod
        printer.Print(delegate(int number) { Console.WriteLine($"Anonim metod: {number}"); });

        // Lambda ifadəsi
        printer.Print(n => Console.WriteLine($"Lambda ifadəsi: {n}"));
    }
}
// Output:
// Anonim metod: 10
// Lambda ifadəsi: 10

using System;

public delegate void ErrorHandler(string message);

class BadProcessor
{
    public ErrorHandler OnError;

    public void Process()
    {
        // Null yoxlaması yoxdur
        OnError("Səhv baş verdi!"); // NullReferenceException riski
    }
}

class Program
{
    static void Main(string[] args)
    {
        BadProcessor processor = new BadProcessor();
        try
        {
            processor.Process();
        }
        catch (NullReferenceException ex)
        {
            Console.WriteLine("Səhv: Deleqata metod təyin edilməyib!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
// Səhv: Deleqata metod təyin edilməyib!
// Səhv mesajı: Object reference not set to an instance of an object.

